noncompliant:
using (var stream = new FileStream("file.txt", FileMode.Open))
{
    // Use stream
    stream.Dispose(); // Noncompliant: disposed twice (using will also dispose)
}

var resource = new MyResource();
resource.Dispose();
resource.Dispose(); // Noncompliant: disposed twice

compliant:
using (var stream = new FileStream("file.txt", FileMode.Open))
{
    // Use stream - will be disposed automatically
}

var resource = new MyResource();
resource.Dispose();
resource = null; // Clear reference to avoid accidental reuse
